class Solution:
    def backspaceCompare(self, s: str, t: str) -> bool:
        i = len(s) - 1
        j = len(t) - 1

        while i >= 0 or j >= 0:
            i = self.process(s, i)
            j = self.process(t, j)

            if i >= 0 and j >= 0:
                if s[i] != t[j]:
                    return False
            else:
                return i < 0 and j < 0

            i -= 1
            j -= 1

        return True

    def process(self, s: str, i: int) -> int:
        skip = 0
        while i >= 0:
            if s[i] == '#':
                skip += 1
                i -= 1
            elif skip > 0:
                skip -= 1
                i -= 1
            else:
                break
        return i

